import{_ as o,o as a,c as r,ae as n}from"./chunks/framework.B6gjLfeO.js";const p=JSON.parse('{"title":"SSO (New)","description":"","frontmatter":{"title":"SSO (New)","slug":"sso-new"},"headers":[],"relativePath":"account-hub/sso-new.md","filePath":"account-hub/sso-new.md"}'),i={name:"account-hub/sso-new.md"};function t(s,e,l,u,c,h){return a(),r("div",null,[...e[0]||(e[0]=[n('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Branch uses Auth0 to enable single sign-on (SSO), which allows you to manage your team&#39;s access to Branch through your identity provider (IdP).</p><p>Using SSO makes it easier to add or remove Branch users, and improves their login experience.</p><h3 id="before-you-begin" tabindex="-1">Before you begin <a class="header-anchor" href="#before-you-begin" aria-label="Permalink to &quot;Before you begin&quot;">​</a></h3><p>Before you begin, ensure you have:</p><ul><li><p>Admin access to your Branch account.</p></li><li><p>Admin access to your organization&#39;s IdP (e.g., Okta, Azure AD) account.</p></li><li><p>SSO enabled for your Branch account.</p><ul><li>Access to SSO requires a Branch plan. Visit our <a href="https://www.branch.io/pricing/" target="_blank" rel="noreferrer">Pricing</a> page or <a href="https://branchdocs.app.link/e/sso-sign-up" target="_blank" rel="noreferrer">contact our Sales team</a> to learn more about pricing and availability.</li></ul></li></ul><h2 id="configure-sso" tabindex="-1">Configure SSO <a class="header-anchor" href="#configure-sso" aria-label="Permalink to &quot;Configure SSO&quot;">​</a></h2><p>To configure SSO, you&#39;ll need to set up Branch in your IdP and enter your IdP information in Branch.</p><p>Choose an SSO guide to follow based on which IdP you use:</p><ul><li><a href="./configure-sso-with-okta.html">Okta</a></li><li><a href="./configure-sso-with-azure.html">Azure</a></li><li><a href="./configure-sso-with-google.html">Google</a></li></ul><p>If you don&#39;t use one of these IdPs, follow our <a href="./configure-sso.html">General SAML</a> guide.</p>',11)])])}const f=o(i,[["render",t]]);export{p as __pageData,f as default};
